{
  "name": "GVCN AI - Classroom Management Pro",
  "description": "A comprehensive classroom management system for teachers, featuring AI-powered student analysis, attendance tracking, behavior monitoring, and financial management."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
