export type Gender = 'Nam' | 'Nữ';
export type AttendanceStatus = 'Present' | 'Late' | 'Absent';

export interface Student {
  id: string;
  studentId: string;
  name: string;
  gender: Gender;
  birthday: string;
  parentPhone: string;
  notes: string;
  points: number;
  attendance: Record<string, AttendanceStatus>; // date string -> status
}

export interface Activity {
  id: string;
  studentId: string;
  studentName: string;
  type: 'PointChange' | 'Attendance' | 'Note';
  content: string;
  value?: number;
  timestamp: number;
}

export interface Transaction {
  id: string;
  type: 'Income' | 'Expense';
  amount: number;
  description: string;
  date: string;
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  priority: 'Low' | 'Medium' | 'High';
  dueDate?: string;
}

export enum ViewMode {
  Dashboard = 'dashboard',
  Students = 'students',
  Classroom = 'classroom',
  Finance = 'finance',
  Tasks = 'tasks',
  AI = 'ai'
}

import React from 'react';
import { LayoutDashboard, Users, UserCheck, Wallet, CheckSquare, Sparkles } from 'lucide-react';
import { ViewMode } from './types';

export const NAV_ITEMS = [
  { id: ViewMode.Dashboard, label: 'Tổng quan', icon: <LayoutDashboard size={20} /> },
  { id: ViewMode.Students, label: 'Học sinh', icon: <Users size={20} /> },
  { id: ViewMode.Classroom, label: 'Lớp & Nề nếp', icon: <UserCheck size={20} /> },
  { id: ViewMode.Finance, label: 'Quỹ lớp', icon: <Wallet size={20} /> },
  { id: ViewMode.Tasks, label: 'Việc cần làm', icon: <CheckSquare size={20} /> },
  { id: ViewMode.AI, label: 'Trợ lý AI', icon: <Sparkles size={20} /> },
];

export const INITIAL_STUDENTS = [
  { id: '1', studentId: 'HS001', name: 'Nguyễn Văn An', gender: 'Nam', birthday: '2012-05-15', parentPhone: '0901234567', notes: 'Học sinh giỏi Toán', points: 10, attendance: {} },
  { id: '2', studentId: 'HS002', name: 'Trần Thị Bình', gender: 'Nữ', birthday: '2012-10-20', parentPhone: '0912345678', notes: 'Hăng hái phát biểu', points: 15, attendance: {} },
  { id: '3', studentId: 'HS003', name: 'Lê Hoàng Cường', gender: 'Nam', birthday: '2012-03-10', parentPhone: '0923456789', notes: 'Cần chú ý nề nếp', points: -5, attendance: {} },
];

import { GoogleGenAI, Type } from "@google/genai";
import { Student, Activity } from "../types";

const API_KEY = process.env.API_KEY || '';

export const analyzeStudent = async (student: Student, activities: Activity[]) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const historyText = activities
    .map(a => `${new Date(a.timestamp).toLocaleDateString()}: ${a.content}`)
    .join('\n');

  const prompt = `Phân tích hồ sơ và lịch sử hoạt động của học sinh sau:
  Họ tên: ${student.name}
  Giới tính: ${student.gender}
  Ngày sinh: ${student.birthday}
  Điểm thi đua hiện tại: ${student.points}
  Ghi chú giáo viên: ${student.notes}

  Lịch sử hoạt động gần đây:
  ${historyText}

  Hãy đưa ra nhận xét chuyên sâu bằng tiếng Việt. Trả về định dạng JSON.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rating: { type: Type.STRING, description: 'Đánh giá chung (Tốt/Khá/Cần cố gắng)' },
            keywords: { type: Type.ARRAY, items: { type: Type.STRING }, description: 'Các từ khóa đặc điểm' },
            advice: { type: Type.STRING, description: 'Lời khuyên giáo dục' },
            sentiment: { type: Type.STRING, description: 'Sắc thái cảm xúc của học sinh gần đây' }
          },
          required: ["rating", "keywords", "advice"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Analysis error:", error);
    return null;
  }
};

export const generateTaskChecklist = async (taskTitle: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const prompt = `Tôi là giáo viên chủ nhiệm. Tôi cần thực hiện công việc: "${taskTitle}". 
  Hãy liệt kê các bước thực hiện chi tiết (checklist) để hoàn thành tốt công việc này. 
  Trả về danh sách các chuỗi văn bản dạng JSON.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Checklist error:", error);
    return [];
  }
};

export const chatWithAI = async (message: string, context: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: message,
    config: {
      systemInstruction: `Bạn là một trợ lý ảo chuyên gia giáo dục (GVCN AI). 
      Bạn hỗ trợ giáo viên chủ nhiệm tại Việt Nam. 
      Ngôn ngữ: Tiếng Việt sư phạm, gần gũi nhưng chuyên nghiệp.
      Bối cảnh hiện tại: ${context}`
    }
  });
  return response.text;
};

import React from 'react';
import { User, Cake, TrendingUp, TrendingDown, Clock, XCircle, CheckCircle } from 'lucide-react';
import { Student, AttendanceStatus } from '../types';

interface StudentCardProps {
  student: Student;
  currentDate: string;
  onAttendance: (status: AttendanceStatus) => void;
  onPoints: (delta: number) => void;
  onSelect: () => void;
}

const StudentCard: React.FC<StudentCardProps> = ({ student, currentDate, onAttendance, onPoints, onSelect }) => {
  const status = student.attendance[currentDate] || 'Present';
  const isBirthday = React.useMemo(() => {
    if (!student.birthday) return false;
    const today = new Date();
    const bday = new Date(student.birthday);
    return today.getDate() === bday.getDate() && today.getMonth() === bday.getMonth();
  }, [student.birthday]);

  const getStatusColor = () => {
    switch (status) {
      case 'Absent': return 'bg-red-50 border-red-200';
      case 'Late': return 'bg-orange-50 border-orange-200';
      default: return 'bg-white border-gray-200';
    }
  };

  return (
    <div 
      className={`relative p-4 border rounded-xl shadow-sm transition-all hover:shadow-md ${getStatusColor()} ${isBirthday ? 'ring-2 ring-yellow-400' : ''}`}
    >
      {isBirthday && (
        <div className="absolute -top-3 -right-2 bg-yellow-400 text-white p-1 rounded-full animate-bounce shadow-lg">
          <Cake size={16} />
        </div>
      )}

      <div className="flex items-start justify-between mb-3" onClick={onSelect}>
        <div className="flex items-center gap-3 cursor-pointer">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center ${student.gender === 'Nam' ? 'bg-blue-100 text-blue-600' : 'bg-pink-100 text-pink-600'}`}>
            <User size={24} />
          </div>
          <div>
            <h3 className="font-bold text-gray-800 line-clamp-1">{student.name}</h3>
            <p className="text-xs text-gray-500">{student.studentId}</p>
          </div>
        </div>
        <div className={`text-sm font-bold px-2 py-1 rounded-lg ${student.points >= 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
          {student.points > 0 ? '+' : ''}{student.points}
        </div>
      </div>

      <div className="flex gap-1 mb-4">
        <button 
          onClick={() => onAttendance('Present')}
          className={`flex-1 flex flex-col items-center py-2 rounded-lg transition-colors ${status === 'Present' ? 'bg-green-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
        >
          <CheckCircle size={16} />
          <span className="text-[10px] mt-1">Đủ</span>
        </button>
        <button 
          onClick={() => onAttendance('Late')}
          className={`flex-1 flex flex-col items-center py-2 rounded-lg transition-colors ${status === 'Late' ? 'bg-orange-500 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
        >
          <Clock size={16} />
          <span className="text-[10px] mt-1">Muộn</span>
        </button>
        <button 
          onClick={() => onAttendance('Absent')}
          className={`flex-1 flex flex-col items-center py-2 rounded-lg transition-colors ${status === 'Absent' ? 'bg-red-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
        >
          <XCircle size={16} />
          <span className="text-[10px] mt-1">Vắng</span>
        </button>
      </div>

      <div className="flex gap-2">
        <button 
          onClick={() => onPoints(1)}
          className="flex-1 py-1.5 bg-blue-50 text-blue-600 rounded-lg text-xs font-semibold hover:bg-blue-100 transition-colors flex items-center justify-center gap-1"
        >
          <TrendingUp size={14} /> +1
        </button>
        <button 
          onClick={() => onPoints(-1)}
          className="flex-1 py-1.5 bg-gray-50 text-gray-600 rounded-lg text-xs font-semibold hover:bg-gray-100 transition-colors flex items-center justify-center gap-1"
        >
          <TrendingDown size={14} /> -1
        </button>
      </div>
    </div>
  );
};

export default StudentCard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Menu, X, Bell, Search, Plus, 
  Trash2, Download, Upload, Info,
  MessageSquare, Send, Sparkles, Loader2,
  PieChart as PieChartIcon
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Cell as PieCell } from 'recharts';
import { 
  Student, Activity, Transaction, Task, ViewMode, AttendanceStatus 
} from './types';
import { NAV_ITEMS, INITIAL_STUDENTS } from './constants';
import { analyzeStudent, generateTaskChecklist, chatWithAI } from './services/geminiService';
import StudentCard from './components/StudentCard';

const App: React.FC = () => {
  // --- State ---
  const [view, setView] = useState<ViewMode>(ViewMode.Dashboard);
  const [students, setStudents] = useState<Student[]>([]);
  const [activities, setActivities] = useState<Activity[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [activeStudent, setActiveStudent] = useState<Student | null>(null);

  // --- Persistence ---
  useEffect(() => {
    const savedStudents = localStorage.getItem('gvcn_students');
    const savedActivities = localStorage.getItem('gvcn_activities');
    const savedTransactions = localStorage.getItem('gvcn_transactions');
    const savedTasks = localStorage.getItem('gvcn_tasks');

    if (savedStudents) setStudents(JSON.parse(savedStudents));
    else setStudents(INITIAL_STUDENTS);

    if (savedActivities) setActivities(JSON.parse(savedActivities));
    if (savedTransactions) setTransactions(JSON.parse(savedTransactions));
    if (savedTasks) setTasks(JSON.parse(savedTasks));
  }, []);

  useEffect(() => {
    localStorage.setItem('gvcn_students', JSON.stringify(students));
    localStorage.setItem('gvcn_activities', JSON.stringify(activities));
    localStorage.setItem('gvcn_transactions', JSON.stringify(transactions));
    localStorage.setItem('gvcn_tasks', JSON.stringify(tasks));
  }, [students, activities, transactions, tasks]);

  const today = new Date().toISOString().split('T')[0];

  // --- Handlers ---
  const handleAddStudent = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newStudent: Student = {
      id: Date.now().toString(),
      studentId: `HS${(students.length + 1).toString().padStart(3, '0')}`,
      name: formData.get('name') as string,
      gender: formData.get('gender') as any,
      birthday: formData.get('birthday') as string,
      parentPhone: formData.get('phone') as string,
      notes: formData.get('notes') as string,
      points: 0,
      attendance: {}
    };
    setStudents([...students, newStudent]);
    e.currentTarget.reset();
  };

  const deleteStudent = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa học sinh này?')) {
      setStudents(students.filter(s => s.id !== id));
      setActivities(activities.filter(a => a.studentId !== id));
    }
  };

  const updateAttendance = (studentId: string, status: AttendanceStatus) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) {
        return { ...s, attendance: { ...s.attendance, [today]: status } };
      }
      return s;
    }));

    const student = students.find(s => s.id === studentId);
    if (student) {
      const newActivity: Activity = {
        id: Date.now().toString(),
        studentId,
        studentName: student.name,
        type: 'Attendance',
        content: `Điểm danh: ${status === 'Present' ? 'Có mặt' : status === 'Late' ? 'Đi muộn' : 'Vắng mặt'}`,
        timestamp: Date.now()
      };
      setActivities([newActivity, ...activities]);
    }
  };

  const changePoints = (studentId: string, delta: number) => {
    setStudents(prev => prev.map(s => {
      if (s.id === studentId) return { ...s, points: s.points + delta };
      return s;
    }));

    const student = students.find(s => s.id === studentId);
    if (student) {
      const newActivity: Activity = {
        id: Date.now().toString(),
        studentId,
        studentName: student.name,
        type: 'PointChange',
        content: `${delta > 0 ? 'Cộng' : 'Trừ'} ${Math.abs(delta)} điểm thi đua`,
        value: delta,
        timestamp: Date.now()
      };
      setActivities([newActivity, ...activities]);
    }
  };

  const addTransaction = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newTx: Transaction = {
      id: Date.now().toString(),
      type: formData.get('type') as any,
      amount: Number(formData.get('amount')),
      description: formData.get('description') as string,
      date: formData.get('date') as string
    };
    setTransactions([newTx, ...transactions]);
    e.currentTarget.reset();
  };

  const addTask = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newTask: Task = {
      id: Date.now().toString(),
      title: formData.get('title') as string,
      completed: false,
      priority: formData.get('priority') as any,
      dueDate: formData.get('dueDate') as string
    };
    setTasks([newTask, ...tasks]);
    e.currentTarget.reset();
  };

  const handleAiAnalysis = async (student: Student) => {
    setIsLoading(true);
    const studentActivities = activities.filter(a => a.studentId === student.id);
    const result = await analyzeStudent(student, studentActivities);
    setAiAnalysis(result);
    setActiveStudent(student);
    setIsLoading(false);
  };

  const handleAiChecklist = async (task: Task) => {
    setIsLoading(true);
    const checklist = await generateTaskChecklist(task.title);
    alert(`Gợi ý các bước cho "${task.title}":\n\n` + checklist.join('\n'));
    setIsLoading(false);
  };

  // --- Stats Helpers ---
  const stats = useMemo(() => {
    const total = students.length;
    const vắng = students.filter(s => s.attendance[today] === 'Absent').length;
    const muộn = students.filter(s => s.attendance[today] === 'Late').length;
    const present = students.filter(s => s.attendance[today] === 'Present' || !s.attendance[today]).length;
    const fund = transactions.reduce((acc, tx) => tx.type === 'Income' ? acc + tx.amount : acc - tx.amount, 0);

    const chartData = students.slice(0, 10).map(s => ({ name: s.name, points: s.points }));

    return { total, vắng, muộn, present, fund, chartData };
  }, [students, transactions, today]);

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    s.studentId.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // --- Render Components ---
  const renderDashboard = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Sĩ số', value: stats.total, color: 'blue' },
          { label: 'Có mặt', value: stats.present, color: 'green' },
          { label: 'Vắng/Muộn', value: `${stats.vắng}/${stats.muộn}`, color: 'red' },
          { label: 'Quỹ lớp', value: stats.fund.toLocaleString() + 'đ', color: 'purple' }
        ].map((item, idx) => (
          <div key={idx} className={`p-6 bg-white border border-gray-100 rounded-2xl shadow-sm`}>
            <p className="text-sm font-medium text-gray-500 uppercase">{item.label}</p>
            <p className={`text-3xl font-bold mt-1 text-${item.color}-600`}>{item.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
            <TrendingUp size={20} className="text-blue-500" />
            Xếp hạng thi đua (Top 10)
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" fontSize={12} />
                <YAxis />
                <Tooltip />
                <Bar dataKey="points" fill="#3b82f6" radius={[4, 4, 0, 0]}>
                  {stats.chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.points >= 0 ? '#10b981' : '#ef4444'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm overflow-hidden flex flex-col">
          <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
            <Clock size={20} className="text-orange-500" />
            Hoạt động gần đây
          </h3>
          <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
            {activities.length === 0 ? (
              <p className="text-center text-gray-400 py-10">Chưa có hoạt động nào hôm nay</p>
            ) : (
              <div className="relative space-y-6 before:absolute before:left-2 before:top-2 before:bottom-2 before:w-px before:bg-gray-200">
                {activities.slice(0, 8).map((activity) => (
                  <div key={activity.id} className="relative pl-8">
                    <div className={`absolute left-0 top-1 w-4 h-4 rounded-full border-2 border-white shadow-sm ${
                      activity.type === 'PointChange' ? (activity.value! > 0 ? 'bg-green-500' : 'bg-red-500') :
                      activity.type === 'Attendance' ? 'bg-blue-500' : 'bg-gray-400'
                    }`} />
                    <div className="text-sm font-semibold text-gray-800">{activity.studentName}</div>
                    <div className="text-sm text-gray-600">{activity.content}</div>
                    <div className="text-xs text-gray-400 mt-0.5">{new Date(activity.timestamp).toLocaleTimeString('vi-VN')}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );

  const renderStudents = () => (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder="Tìm kiếm học sinh theo tên hoặc mã..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
          />
        </div>
        <button 
          onClick={() => document.getElementById('add-student-modal')?.classList.remove('hidden')}
          className="bg-blue-600 text-white px-6 py-2 rounded-xl font-semibold hover:bg-blue-700 transition-colors flex items-center gap-2"
        >
          <Plus size={18} /> Thêm mới
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Mã HS</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Họ tên</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Giới tính</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Ngày sinh</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">SĐT Phụ huynh</th>
                <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Thao tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredStudents.map((s) => (
                <tr key={s.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4 text-sm font-medium text-gray-700">{s.studentId}</td>
                  <td className="px-6 py-4 text-sm font-bold text-gray-900">{s.name}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{s.gender}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{s.birthday}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{s.parentPhone}</td>
                  <td className="px-6 py-4">
                    <div className="flex gap-2">
                      <button 
                        onClick={() => handleAiAnalysis(s)}
                        className="p-2 text-purple-600 hover:bg-purple-50 rounded-lg"
                        title="Phân tích AI"
                      >
                        <Sparkles size={18} />
                      </button>
                      <button 
