              <button onClick={async () => { const msg = (document.getElementById('ai-msg') as HTMLTextAreaElement).value; setIsLoading(true); const r = await chatWithAI(msg, "Đang ở chế độ trợ lý ảo"); alert(r); setIsLoading(false); }} className="w-full bg-purple-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-xl"><Send size={20}/> Gửi yêu cầu</button>
            </div>
